import{_ as a,o as r,c as d,a2 as e}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"🌾 黃豆市場深度分析報告","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/黃豆研究/黃豆市場深度分析報告.md","filePath":"Deep32Q知識庫/產業洞察/黃豆研究/黃豆市場深度分析報告.md"}'),o={name:"Deep32Q知識庫/產業洞察/黃豆研究/黃豆市場深度分析報告.md"};function l(n,t,i,h,s,g){return r(),d("div",null,[...t[0]||(t[0]=[e(`<h1 id="🌾-黃豆市場深度分析報告" tabindex="-1">🌾 黃豆市場深度分析報告 <a class="header-anchor" href="#🌾-黃豆市場深度分析報告" aria-label="Permalink to &quot;🌾 黃豆市場深度分析報告&quot;">​</a></h1><p><strong>報告日期：</strong> 2026-04-27 <strong>研究範圍：</strong> 全球黃豆市場（美國、巴西、中國） <strong>資料來源：</strong> USDA、CBOT、TradingView、本地搜尋引擎</p><hr><h2 id="一、市場概況" tabindex="-1">一、市場概況 <a class="header-anchor" href="#一、市場概況" aria-label="Permalink to &quot;一、市場概況&quot;">​</a></h2><h3 id="_1-1-最新報價" tabindex="-1">1.1 最新報價 <a class="header-anchor" href="#_1-1-最新報價" aria-label="Permalink to &quot;1.1 最新報價&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指標</th><th>數值</th><th>變動</th></tr></thead><tbody><tr><td>CBOT 黃豆期貨（ZSN6）</td><td>1180.5 美分/蒲式耳</td><td>+0.13%</td></tr><tr><td>FOB Santos 黃豆</td><td>451.4 USD</td><td>+0.13%</td></tr><tr><td>YTD 漲幅</td><td>+12.29%</td><td>—</td></tr><tr><td>近 1 個月漲幅</td><td>+4.15%</td><td>—</td></tr></tbody></table><h3 id="_1-2-價格走勢-近-3-個月" tabindex="-1">1.2 價格走勢（近 3 個月） <a class="header-anchor" href="#_1-2-價格走勢-近-3-個月" aria-label="Permalink to &quot;1.2 價格走勢（近 3 個月）&quot;">​</a></h3><ul><li><strong>高點</strong>：約 1250 美分（3 月初）</li><li><strong>低點</strong>：約 1100 美分（2 月中旬）</li><li><strong>當前</strong>：1180.5 美分，區間中段偏上</li><li><strong>趨勢</strong>：震盪中緩步上行，短期均線交織，市場盤整</li></ul><h3 id="_1-3-技術面" tabindex="-1">1.3 技術面 <a class="header-anchor" href="#_1-3-技術面" aria-label="Permalink to &quot;1.3 技術面&quot;">​</a></h3><table tabindex="0"><thead><tr><th>類型</th><th>位階</th></tr></thead><tbody><tr><td>第一壓力</td><td>1200 美分（心理關口）</td></tr><tr><td>第二壓力</td><td>1230 美分</td></tr><tr><td>第一支撐</td><td>1150 美分</td></tr><tr><td>第二支撐</td><td>1120 美分</td></tr></tbody></table><p>技術指標：中立至賣出訊號，短期有回測支撐需求。</p><hr><h2 id="二、供需基本面" tabindex="-1">二、供需基本面 <a class="header-anchor" href="#二、供需基本面" aria-label="Permalink to &quot;二、供需基本面&quot;">​</a></h2><h3 id="_2-1-usda-2026-27-預測" tabindex="-1">2.1 USDA 2026/27 預測 <a class="header-anchor" href="#_2-1-usda-2026-27-預測" aria-label="Permalink to &quot;2.1 USDA 2026/27 預測&quot;">​</a></h3><table tabindex="0"><thead><tr><th>項目</th><th>2025/26 預估</th><th>2026/27 預測</th><th>變動</th></tr></thead><tbody><tr><td>美國種植面積</td><td>—</td><td>增加（玉米轉種）</td><td>+4.8M acres</td></tr><tr><td>結庫存</td><td>355M bushels</td><td>355M bushels</td><td>持平</td></tr><tr><td>季均農場價</td><td>—</td><td>微降</td><td>—</td></tr></tbody></table><p><strong>關鍵：</strong> USDA 預測 2026/27 結庫存 355M bushels，與 2025/26 幾乎持平。種植面積增加但被需求成長抵消。</p><h3 id="_2-2-全球供應格局" tabindex="-1">2.2 全球供應格局 <a class="header-anchor" href="#_2-2-全球供應格局" aria-label="Permalink to &quot;2.2 全球供應格局&quot;">​</a></h3><table tabindex="0"><thead><tr><th>國家</th><th>2026/27 產量預估</th><th>特徵</th></tr></thead><tbody><tr><td><strong>巴西</strong></td><td>177.8M 噸（歷史新高）</td><td>連續三年破紀錄，出口同步成長</td></tr><tr><td><strong>美國</strong></td><td>預估增加（玉米轉種）</td><td>農民因獲利更高轉種黃豆</td></tr><tr><td><strong>阿根廷</strong></td><td>待更新</td><td>受乾旱風險影響</td></tr></tbody></table><h3 id="_2-3-巴西-全球供應主導者" tabindex="-1">2.3 巴西：全球供應主導者 <a class="header-anchor" href="#_2-3-巴西-全球供應主導者" aria-label="Permalink to &quot;2.3 巴西：全球供應主導者&quot;">​</a></h3><ul><li><strong>Abiove 上調</strong> 2026 年黃豆收割預估至 <strong>177.85M 噸</strong>（+70 萬噸）</li><li><strong>連續三年破紀錄</strong>，出口同步成長</li><li><strong>美國農民轉種</strong>：因黃豆獲利高於玉米，2026 年美國黃豆種植面積預估增加 480 萬英畝</li><li><strong>風險</strong>：巴西大豐收可能壓低全球價格</li></ul><hr><h2 id="三、天氣與種植進度" tabindex="-1">三、天氣與種植進度 <a class="header-anchor" href="#三、天氣與種植進度" aria-label="Permalink to &quot;三、天氣與種植進度&quot;">​</a></h2><h3 id="_3-1-美國中西部" tabindex="-1">3.1 美國中西部 <a class="header-anchor" href="#_3-1-美國中西部" aria-label="Permalink to &quot;3.1 美國中西部&quot;">​</a></h3><ul><li><strong>種植季</strong>：4-5 月，目前進度正常偏快</li><li><strong>天氣風險</strong>：中西部春季降雨偏多，可能延遲種植</li><li><strong>關鍵觀察</strong>：種植窗口期天氣將決定最終面積</li></ul><h3 id="_3-2-巴西" tabindex="-1">3.2 巴西 <a class="header-anchor" href="#_3-2-巴西" aria-label="Permalink to &quot;3.2 巴西&quot;">​</a></h3><ul><li><strong>收割進度</strong>：2026 年收割已接近尾聲，產量創紀錄</li><li><strong>二季作物</strong>：玉米種植面積可能因黃豆獲利更高而減少</li><li><strong>風險</strong>：若收割期遇雨，可能影響品質</li></ul><h3 id="_3-3-阿根廷" tabindex="-1">3.3 阿根廷 <a class="header-anchor" href="#_3-3-阿根廷" aria-label="Permalink to &quot;3.3 阿根廷&quot;">​</a></h3><ul><li><strong>乾旱風險</strong>：拉尼娜現象可能影響產量</li><li><strong>關鍵時期</strong>：12-2 月開花結莢期是關鍵</li></ul><hr><h2 id="四、政策與貿易戰影響" tabindex="-1">四、政策與貿易戰影響 <a class="header-anchor" href="#四、政策與貿易戰影響" aria-label="Permalink to &quot;四、政策與貿易戰影響&quot;">​</a></h2><h3 id="_4-1-美中貿易戰" tabindex="-1">4.1 美中貿易戰 <a class="header-anchor" href="#_4-1-美中貿易戰" aria-label="Permalink to &quot;4.1 美中貿易戰&quot;">​</a></h3><table tabindex="0"><thead><tr><th>措施</th><th>影響</th></tr></thead><tbody><tr><td>美國對中國關稅 145%</td><td>黃豆出口受阻</td></tr><tr><td>中國報復性關稅</td><td>迫使需求轉向巴西</td></tr><tr><td>農業補貼</td><td>美國政府提供補貼緩衝</td></tr></tbody></table><h3 id="_4-2-中國需求轉移" tabindex="-1">4.2 中國需求轉移 <a class="header-anchor" href="#_4-2-中國需求轉移" aria-label="Permalink to &quot;4.2 中國需求轉移&quot;">​</a></h3><ul><li><strong>巴西成為首選</strong>：中國從巴西進口黃豆比例持續上升</li><li><strong>供應鏈多元化</strong>：中國減少對美國依賴，增加阿根廷、烏拉圭等來源</li><li><strong>匯率影響</strong>：美元走強不利美國出口，人民幣走勢影響中國進口成本</li></ul><h3 id="_4-3-貿易流向重組" tabindex="-1">4.3 貿易流向重組 <a class="header-anchor" href="#_4-3-貿易流向重組" aria-label="Permalink to &quot;4.3 貿易流向重組&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>傳統：美國 → 中國（最大買賣）</span></span>
<span class="line"><span>現在：巴西 → 中國（首選）+ 美國 → 中國（減少）+ 阿根廷 → 中國（增加）</span></span></code></pre></div><hr><h2 id="五、風險矩陣" tabindex="-1">五、風險矩陣 <a class="header-anchor" href="#五、風險矩陣" aria-label="Permalink to &quot;五、風險矩陣&quot;">​</a></h2><table tabindex="0"><thead><tr><th>風險類型</th><th>發生機率</th><th>影響程度</th><th>監控指標</th></tr></thead><tbody><tr><td>巴西大豐收壓低價格</td><td>高</td><td>中</td><td>巴西產量預估、出口數據</td></tr><tr><td>美國天氣異常</td><td>中</td><td>高</td><td>中西部降雨、種植進度</td></tr><tr><td>貿易戰再升級</td><td>中</td><td>高</td><td>中美談判進展、關稅政策</td></tr><tr><td>中國需求放緩</td><td>低-中</td><td>高</td><td>中國進口數據、豬肉產量</td></tr><tr><td>阿根廷乾旱</td><td>中</td><td>中</td><td>拉尼娜強度、降雨數據</td></tr></tbody></table><hr><h2 id="六、投資-交易建議" tabindex="-1">六、投資/交易建議 <a class="header-anchor" href="#六、投資-交易建議" aria-label="Permalink to &quot;六、投資/交易建議&quot;">​</a></h2><h3 id="_6-1-短期-1-3-個月" tabindex="-1">6.1 短期（1-3 個月） <a class="header-anchor" href="#_6-1-短期-1-3-個月" aria-label="Permalink to &quot;6.1 短期（1-3 個月）&quot;">​</a></h3><ul><li><strong>方向</strong>：中性偏多，震盪格局</li><li><strong>策略</strong>：1150 以下逢低佈局，1200 以上減碼</li><li><strong>風險</strong>：巴西收割結束後的供給壓力</li></ul><h3 id="_6-2-中期-3-6-個月" tabindex="-1">6.2 中期（3-6 個月） <a class="header-anchor" href="#_6-2-中期-3-6-個月" aria-label="Permalink to &quot;6.2 中期（3-6 個月）&quot;">​</a></h3><ul><li><strong>關鍵事件</strong>：美國種植季天氣、中國進口數據</li><li><strong>方向</strong>：若天氣正常，偏空（巴西豐收 + 美國擴種）</li><li><strong>策略</strong>：1200 以上可佈局空單</li></ul><h3 id="_6-3-長期-6-12-個月" tabindex="-1">6.3 長期（6-12 個月） <a class="header-anchor" href="#_6-3-長期-6-12-個月" aria-label="Permalink to &quot;6.3 長期（6-12 個月）&quot;">​</a></h3><ul><li><strong>結構性因素</strong>：巴西持續擴產、中美貿易戰常態化</li><li><strong>方向</strong>：偏空，但需關注天氣黑天鵝</li><li><strong>關鍵觀察</strong>：2027 年巴西能否再破紀錄</li></ul><hr><h2 id="七、結論" tabindex="-1">七、結論 <a class="header-anchor" href="#七、結論" aria-label="Permalink to &quot;七、結論&quot;">​</a></h2><ol><li><strong>供給充裕</strong>：巴西創紀錄 + 美國擴種，全球供給偏鬆</li><li><strong>需求穩定</strong>：中國進口需求維持高檔，但轉向巴西</li><li><strong>價格展望</strong>：短期震盪，中期偏空，長期需關注天氣</li><li><strong>最大變數</strong>：美國種植季天氣 + 中國需求變化</li></ol><hr><p><em>本報告由 Gale 透過本地搜尋引擎（DuckDuckGo）整理，資料截至 2026-04-27。</em><em>免責聲明：本報告僅供研究參考，不構成投資建議。</em></p>`,52)])])}const c=a(o,[["render",l]]);export{u as __pageData,c as default};
